parameters.jsCode:
const input = $json || {};

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function asBoolean(value, fallback = false) {
  if (typeof value === "boolean") return value;
  if (typeof value === "number") return value === 1;
  if (typeof value === "string") {
    const v = value.toLowerCase().trim();
    if (["true", "1", "yes", "si", "sí"].includes(v)) return true;
    if (["false", "0", "no"].includes(v)) return false;
  }
  return fallback;
}

function pickFirst(...values) {
  for (const value of values) {
    const cleaned = clean(value);
    if (cleaned) return cleaned;
  }
  return "";
}

function pickFirstNumber(...values) {
  for (const value of values) {
    if (value === null || value === undefined || value === "") continue;
    const n = Number(value);
    if (Number.isFinite(n) && n > 0) return n;
  }
  return null;
}

const raw = input.raw_input || input;

const inputEvent = asObject(input.input_event || raw.input_event || raw.message || {});
const serviceContext = asObject(input.service_context || raw.service_context || raw.business_context?.service_context || {});
const customerContext = asObject(input.customer_context || raw.customer_context || raw.customer || {});
const businessContext = asObject(input.business_context || raw.business_context || {});
const caseContext = asObject(input.case_context || raw.case_context || raw.active_case || {});
const caseUpdate = asObject(input.case_update || raw.case_update || {});
const decision = asObject(input.decision || raw.decision || {});
const message = asObject(input.message || raw.message || {});
const agent = asObject(input.agent || raw.agent || {});

const handoffReason = pickFirst(
  input.handoff_reason,
  raw.handoff_reason,
  inputEvent.handoff_reason,
  caseUpdate.handoff_reason,
  decision.handoff_reason,
  input.next_steps?.handoff_reason,
  "out_of_scope"
);

const waId = pickFirst(
  inputEvent.wa_id,
  inputEvent.phone_normalized,
  inputEvent.from,
  inputEvent.phone,
  raw.wa_id,
  raw.phone_normalized,
  raw.from,
  customerContext.phone,
  customerContext.phone_normalized,
  caseContext.wa_id
);

const phoneNormalized = pickFirst(
  inputEvent.phone_normalized,
  inputEvent.wa_id,
  raw.phone_normalized,
  raw.wa_id,
  customerContext.phone_normalized,
  customerContext.phone,
  caseContext.wa_id
);

const providerMessageId = pickFirst(
  inputEvent.provider_message_id,
  inputEvent.message_id,
  inputEvent.id,
  raw.provider_message_id,
  raw.message_id,
  raw.id
);

const contextMessageId = pickFirst(inputEvent.context_message_id, raw.context_message_id);

const messageText = pickFirst(
  inputEvent.message_text,
  inputEvent.text,
  message.text,
  raw.message_text,
  raw.text,
  raw.reply_text
);

const dominantService = pickFirst(
  serviceContext.dominant_service,
  serviceContext.service_code,
  caseUpdate.service_code,
  caseContext.service_code,
  raw.service_code
);

let serviceCode = pickFirst(
  caseUpdate.service_code,
  serviceContext.service_code,
  serviceContext.dominant_service,
  caseContext.service_code,
  raw.service_code,
  "organic_whatsapp"
);

if (serviceCode === "armado") serviceCode = "postventa_armado";
if (serviceCode === "mantencion" || serviceCode === "mantención") serviceCode = "postventa_mantencion";

const sourceTable = pickFirst(
  caseUpdate.source_table,
  serviceContext.source_table,
  caseContext.source_table,
  raw.source_table
) || null;

const sourceId = pickFirstNumber(
  caseUpdate.source_id,
  serviceContext.source_id,
  caseContext.source_id,
  raw.source_id
);

const idOrder = pickFirstNumber(
  caseUpdate.id_order,
  serviceContext.id_order,
  serviceContext.assembly_context?.[0]?.id_order,
  serviceContext.maintenance_context?.[0]?.id_order,
  caseContext.id_order,
  raw.id_order,
  customerContext.id_order,
  customerContext.last_order_id
);

const idCustomer = pickFirstNumber(
  caseUpdate.id_customer,
  serviceContext.id_customer,
  serviceContext.maintenance_context?.[0]?.id_customer,
  caseContext.id_customer,
  raw.id_customer,
  customerContext.id_customer
);

const invoiceNumber = pickFirstNumber(
  caseUpdate.invoice_number,
  serviceContext.invoice_number,
  serviceContext.maintenance_context?.[0]?.invoice_number,
  caseContext.invoice_number,
  raw.invoice_number,
  customerContext.invoice_number
);

let caseOriginType = pickFirst(
  caseUpdate.case_origin_type,
  serviceContext.case_origin_type,
  caseContext.case_origin_type,
  raw.case_origin_type
);

if (!caseOriginType) {
  if (serviceCode === "postventa_armado" || dominantService === "postventa_armado") {
    caseOriginType = "postventa_armado";
  } else if (serviceCode === "postventa_mantencion" || dominantService === "postventa_mantencion") {
    caseOriginType = "postventa_mantencion";
  } else if (sourceTable === "n8n_postventa_queue") {
    caseOriginType = "postventa_armado";
  } else if (sourceTable === "n8n_mantenciones_cardio_queue") {
    caseOriginType = "postventa_mantencion";
  } else if (serviceCode.includes("venta")) {
    caseOriginType = "ventas_whatsapp";
  } else if (serviceCode.includes("garantia")) {
    caseOriginType = "garantia";
  } else if (serviceCode.includes("reclamo")) {
    caseOriginType = "reclamo";
  } else {
    caseOriginType = "organic_whatsapp";
  }
}

const normalized = {
  agent: {
    name: pickFirst(agent.name, "UNKNOWN_AGENT"),
    version: pickFirst(agent.version, "0.1.0")
  },
  decision: {
    action_type: pickFirst(decision.action_type, raw.final_action, raw.recommended_next_action, "handoff_to_human"),
    requires_human: asBoolean(decision.requires_human, false) || asBoolean(raw.requires_human, false) || true,
    confidence: Number(decision.confidence ?? raw.confidence ?? 0),
    risk_level: pickFirst(decision.risk_level, raw.risk_level, "medium"),
    allowed_to_auto_reply: asBoolean(decision.allowed_to_auto_reply, false),
    handoff_reason: handoffReason
  },
  message: {
    channel: pickFirst(message.channel, "whatsapp"),
    text: messageText
  },
  case_update: {
    department: pickFirst(caseUpdate.department, raw.final_department, caseContext.department, "SAC"),
    priority: pickFirst(caseUpdate.priority, raw.case_priority, caseContext.priority, "normal"),
    case_type: pickFirst(caseUpdate.case_type, raw.final_intent, raw.ai_intent, caseContext.case_type, dominantService, "consulta_general"),
    service_code: serviceCode,
    case_origin_type: caseOriginType,
    status: pickFirst(caseUpdate.status, "human_required"),
    source_table: sourceTable,
    source_id: sourceId,
    id_order: idOrder,
    id_customer: idCustomer,
    invoice_number: invoiceNumber,
    handoff_reason: handoffReason
  },
  input_event: {
    wa_id: waId,
    phone_normalized: phoneNormalized,
    contact_name: pickFirst(inputEvent.contact_name, raw.contact_name, customerContext.full_name, customerContext.name, caseContext.contact_name),
    phone_number_id: pickFirst(inputEvent.phone_number_id, raw.phone_number_id),
    provider_message_id: providerMessageId,
    context_message_id: contextMessageId,
    message_type: pickFirst(inputEvent.message_type, raw.message_type, "text"),
    message_text: messageText,
    received_at: pickFirst(inputEvent.received_at, raw.received_at),
    timestamp: pickFirst(inputEvent.timestamp, raw.timestamp),
    handoff_reason: handoffReason
  },
  service_context: {
    ...serviceContext,
    dominant_service: dominantService || serviceCode,
    source_table: sourceTable,
    source_id: sourceId,
    case_origin_type: caseOriginType
  },
  customer_context: customerContext,
  business_context: businessContext,
  case_context: caseContext,
  tool_request: asObject(input.tool_request || raw.tool_request),
  events: asArray(input.events || raw.events),
  next_steps: asObject(input.next_steps || raw.next_steps),
  safety: asObject(input.safety || raw.safety),
  handoff_reason: handoffReason,
  raw_input: raw,
  validation: {
    can_create_case: !!waId,
    missing_required_fields: waId ? [] : ["wa_id"]
  }
};

return [{ json: normalized }];

const data = $json;

let handoffDepartment = data.case_update.department || "SAC";
let priority = data.case_update.priority || "normal";
let reason = "human_review_required";

const risk = data.decision.risk_level;
const action = data.decision.action_type;
const caseType = data.case_update.case_type;

if (risk === "high") {
  priority = "high";
  reason = "high_risk_interaction";
}

if (action === "handoff_to_human") {
  reason = "agent_requested_handoff";
}

if (caseType.includes("reclamo")) {
  handoffDepartment = "SAC";
  priority = "high";
  reason = "complaint_case";
}

if (caseType.includes("garantia") || caseType.includes("warranty")) {
  handoffDepartment = "SAC";
  priority = "high";
  reason = "warranty_case";
}

if (caseType.includes("cotizacion")) {
  handoffDepartment = "ventas";
}

if (caseType.includes("armado") || caseType.includes("mantencion")) {
  handoffDepartment = "postventa";
}

if (data.decision.confidence < 0.75) {
  reason = "low_confidence";
}

return [
  {
    json: {
      ...data,
      handoff_decision: {
        mode: "dry_run",
        would_handoff: true,
        handoff_department: handoffDepartment,
        priority,
        reason,
        should_notify_human: true,
        should_auto_reply_customer: false
      }
    }
  }
];

const data = $json || {};
const finalCase = data.final_case || {};
const inputEvent = data.input_event || {};
const customer = data.customer_context || {};
const service = data.service_context || {};
const business = data.business_context || {};
const caseUpdate = data.case_update || {};

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function pickFirst(...values) {
  for (const value of values) {
    const v = clean(value);
    if (v) return v;
  }
  return "";
}

function pickFirstNumber(...values) {
  for (const value of values) {
    if (value === null || value === undefined || value === "") continue;
    const n = Number(value);
    if (Number.isFinite(n) && n > 0) return n;
  }
  return null;
}

function firstArrayItem(value) {
  return Array.isArray(value) && value.length > 0 ? value[0] : {};
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function normalizeDateTime(value) {
  const raw = clean(value);
  if (!raw) return "";

  const normalized = raw.includes("T") ? raw : raw.replace(" ", "T");
  const d = new Date(normalized);

  if (Number.isNaN(d.getTime())) return raw;

  return new Intl.DateTimeFormat("es-CL", {
    timeZone: "America/Santiago",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit"
  }).format(d);
}

function splitDoublePipe(value) {
  const raw = clean(value);
  if (!raw) return [];

  return raw
    .split("||")
    .map(x => clean(x))
    .filter(Boolean);
}

function splitPipe(value) {
  const raw = clean(value);
  if (!raw) return [];

  return raw
    .split("|")
    .map(x => clean(x))
    .filter(Boolean);
}

function normalizeProductNames(...values) {
  for (const value of values) {
    const raw = clean(value);
    if (!raw) continue;

    if (raw.includes("||")) return splitDoublePipe(raw);
    if (raw.includes("|")) return splitPipe(raw);

    return [raw];
  }

  return [];
}

function normalizeProductReferences(...values) {
  for (const value of values) {
    const raw = clean(value);
    if (!raw) continue;

    if (raw.includes("||")) {
      return raw
        .split("||")
        .map(row => {
          const parts = row.split("|").map(x => clean(x));
          return parts[1] || parts[0] || "";
        })
        .filter(Boolean);
    }

    if (raw.includes("|")) return splitPipe(raw);

    return [raw];
  }

  return [];
}

function bool(value) {
  return value === true || value === 1 || value === "1" || String(value).toLowerCase() === "true";
}

const serviceCustomerDetail = asObject(service.customer_detail);
const customerDetail = Object.keys(serviceCustomerDetail).length
  ? serviceCustomerDetail
  : asObject(business.customer_detail);

const assembly = firstArrayItem(
  service.assembly_context ||
  service.recent_assembly ||
  business.recent_assembly ||
  []
);

const maintenance = firstArrayItem(
  service.maintenance_context ||
  service.recent_maintenance ||
  business.recent_maintenance ||
  []
);

const serviceCode = pickFirst(
  finalCase.service_code,
  caseUpdate.service_code,
  service.service_code,
  service.dominant_service,
  data.service_code,
  "organic_whatsapp"
);

const caseOriginType = pickFirst(
  finalCase.case_origin_type,
  caseUpdate.case_origin_type,
  service.case_origin_type,
  data.case_origin_type,
  serviceCode,
  "organic_whatsapp"
);

const sourceTable = pickFirst(
  data.source_table,
  finalCase.source_table,
  service.source_table,
  caseUpdate.source_table
);

const sourceId = pickFirstNumber(
  data.source_id,
  finalCase.source_id,
  service.source_id,
  caseUpdate.source_id
);

const isMaintenance =
  serviceCode.includes("mantencion") ||
  serviceCode.includes("mantención") ||
  caseOriginType.includes("mantencion") ||
  caseOriginType.includes("mantención") ||
  sourceTable === "n8n_mantenciones_cardio_queue" ||
  Object.keys(maintenance).length > 0;

const isAssembly =
  serviceCode.includes("armado") ||
  caseOriginType.includes("armado") ||
  sourceTable === "n8n_postventa_queue" ||
  Object.keys(assembly).length > 0;

let serviceLabel = "WhatsApp orgánico";

if (isAssembly) serviceLabel = "Armado";
if (isMaintenance) serviceLabel = "Mantención";
if (caseOriginType === "reclamo" || serviceCode === "reclamo") serviceLabel = "Reclamo";
if (caseOriginType === "garantia" || caseOriginType === "garantía") serviceLabel = "Garantía";
if (caseOriginType === "ventas_whatsapp") serviceLabel = "Ventas";

const caseId = pickFirstNumber(
  finalCase.id,
  finalCase.conversation_case_id,
  data.case_id,
  data.conversation_case_id
);

const token = pickFirst(
  finalCase.case_view_token,
  data.case_view_token
);

const HUB_BASE_URL = "https://n8n.pesaschile.cl/webhook/hub/case";
const hubCaseUrl = token
  ? `${HUB_BASE_URL}?token=${encodeURIComponent(token)}`
  : "";

const waId = pickFirst(
  finalCase.wa_id,
  inputEvent.wa_id,
  inputEvent.phone_normalized,
  customer.phone,
  customer.phone_normalized,
  maintenance.phone_normalized,
  assembly.phone_normalized,
  data.wa_id,
  data.phone_normalized,
  "Sin teléfono"
);

const customerName = pickFirst(
  customerDetail.full_name,
  [customerDetail.firstname, customerDetail.lastname].filter(Boolean).join(" "),
  finalCase.contact_name,
  customer.full_name,
  customer.name,
  [customer.firstname, customer.lastname].filter(Boolean).join(" "),
  [maintenance.firstname, maintenance.lastname].filter(Boolean).join(" "),
  [assembly.firstname, assembly.lastname].filter(Boolean).join(" "),
  inputEvent.contact_name,
  data.contact_name,
  "Sin nombre"
);

const customerEmail = pickFirst(
  customerDetail.email,
  customer.email,
  maintenance.email,
  assembly.email,
  "Sin correo"
);

const customerRut = pickFirst(
  customerDetail.rut,
  customerDetail.dni,
  customer.rut,
  customer.dni,
  maintenance.rut,
  maintenance.dni,
  assembly.rut,
  assembly.dni,
  "Sin RUT"
);

const addressFull = pickFirst(
  customerDetail.address_full,
  customerDetail.address,
  customer.address_full,
  customer.address,
  customer.delivery_address,
  maintenance.address_full,
  maintenance.address,
  maintenance.delivery_address,
  assembly.address_full,
  assembly.address,
  assembly.delivery_address,
  "Sin dirección informada"
);

const city = pickFirst(
  customerDetail.city,
  customerDetail.comuna,
  customer.city,
  customer.comuna,
  customer.delivery_city,
  maintenance.comuna,
  maintenance.comuna_normalized,
  maintenance.city,
  assembly.comuna,
  assembly.delivery_city,
  assembly.city,
  "Sin comuna informada"
);

const idOrder = pickFirstNumber(
  customerDetail.id_order,
  finalCase.id_order,
  caseUpdate.id_order,
  service.id_order,
  maintenance.id_order,
  assembly.id_order,
  customer.last_order_id,
  customer.id_order,
  data.id_order
);

const invoiceNumber = pickFirstNumber(
  customerDetail.invoice_number,
  finalCase.invoice_number,
  caseUpdate.invoice_number,
  service.invoice_number,
  maintenance.invoice_number,
  assembly.invoice_number,
  customer.invoice_number,
  data.invoice_number
);

const idCustomer = pickFirstNumber(
  customerDetail.id_customer,
  finalCase.id_customer,
  caseUpdate.id_customer,
  customer.id_customer,
  maintenance.id_customer,
  assembly.id_customer,
  data.id_customer
);

const productNames = normalizeProductNames(
  customerDetail.products_full,
  customerDetail.product_names,
  customer.products_full,
  customer.product_names,
  maintenance.product_names,
  maintenance.products_full,
  assembly.product_names,
  assembly.products_full,
  business.product_names,
  business.products_full
);

const productReferences = normalizeProductReferences(
  customerDetail.product_references,
  customerDetail.products_full,
  customer.product_references,
  customer.products_full,
  maintenance.product_references,
  assembly.product_references,
  business.product_references
);

const messageText = pickFirst(
  inputEvent.message_text,
  inputEvent.text,
  data.message?.text,
  data.message_text,
  data.text,
  "Sin mensaje"
);

const replyIntent = pickFirst(
  caseUpdate.case_type,
  finalCase.last_intent,
  service.last_intent,
  maintenance.last_intent,
  assembly.last_intent,
  data.decision?.action_type,
  data.intent,
  "sin_intencion"
);

const replyAction = pickFirst(
  data.action,
  data.response_action,
  service.action,
  maintenance.action,
  assembly.action,
  data.decision?.action_type,
  finalCase.final_action,
  data.action_type,
  "handoff_to_human"
);

const replyAt = pickFirst(
  inputEvent.received_at,
  inputEvent.timestamp,
  finalCase.last_message_at,
  finalCase.updated_at,
  data.received_at,
  data.created_at
);

const maintenanceDetail = {
  exists: isMaintenance,
  id: maintenance.id || null,
  id_order: pickFirstNumber(maintenance.id_order, idOrder),
  invoice_number: pickFirstNumber(maintenance.invoice_number, invoiceNumber),
  stage: pickFirst(maintenance.maintenance_stage, maintenance.stage, "Sin etapa"),
  cycle: pickFirst(maintenance.maintenance_cycle, maintenance.cycle, "Sin ciclo"),
  purchase_date: pickFirst(maintenance.purchase_date, maintenance.created_at, customer.last_order_at, "Sin fecha compra"),
  months_since_purchase: pickFirst(maintenance.months_since_purchase, "Sin meses"),
  maintenance_due_date: pickFirst(maintenance.maintenance_due_date, maintenance.due_date, "Sin fecha objetivo"),
  status: pickFirst(maintenance.status, "Sin status"),
  case_status: pickFirst(maintenance.estado_caso, "Sin estado caso"),
  last_intent: pickFirst(maintenance.last_intent, "Sin última intención"),
  responded: bool(maintenance.respondio),
  requires_human_contact: bool(maintenance.requiere_contacto_humano),
  derivation_channel: pickFirst(maintenance.canal_derivacion, "Sin canal derivación"),
  sac_notified: bool(maintenance.sac_notified),
  contact_reply_sent: bool(maintenance.contact_reply_sent),
  contact_reply_sent_at: pickFirst(maintenance.contact_reply_sent_at, "")
};

const assemblyDetail = {
  exists: isAssembly,
  id: assembly.id || null,
  id_order: pickFirstNumber(assembly.id_order, idOrder),
  invoice_number: pickFirstNumber(assembly.invoice_number, invoiceNumber),
  status: pickFirst(assembly.status, "Sin status"),
  case_status: pickFirst(assembly.estado_caso, "Sin estado caso"),
  purchase_date: pickFirst(assembly.purchase_date, assembly.created_at, customer.last_order_at, "Sin fecha compra"),
  delivery_date: pickFirst(assembly.delivery_date, assembly.delivered_at, "Sin fecha despacho"),
  delivery_address: pickFirst(assembly.delivery_address, assembly.address_full, addressFull),
  delivery_city: pickFirst(assembly.delivery_city, assembly.city, city),
  last_intent: pickFirst(assembly.last_intent, "Sin última intención"),
  responded: bool(assembly.respondio),
  requires_human_contact: bool(assembly.requiere_contacto_humano),
  derivation_channel: pickFirst(assembly.canal_derivacion, "Sin canal derivación"),
  sac_notified: bool(assembly.sac_notified),
  contact_reply_sent: bool(assembly.contact_reply_sent),
  contact_reply_sent_at: pickFirst(assembly.contact_reply_sent_at, "")
};

const department = pickFirst(
  finalCase.department,
  data.handoff_decision?.handoff_department,
  caseUpdate.department,
  isMaintenance || isAssembly ? "Postventa" : "",
  "SAC"
);

const priority = pickFirst(
  finalCase.priority,
  data.handoff_decision?.priority,
  caseUpdate.priority,
  "normal"
);

const status = pickFirst(
  finalCase.status,
  caseUpdate.status,
  "human_required"
);

let emailTo = "sac@pesaschile.cl";

if (department === "Ventas") emailTo = "ventas@pesaschile.cl";
if (department === "Marketing") emailTo = "marketing@pesaschile.cl";
if (department === "Postventa" || department === "SAC") emailTo = "sac@pesaschile.cl";

const emailSubject = `[${department}] WhatsApp - ${serviceLabel} | OP ${idOrder || "SIN-OP"} | ${customerName || waId}`;

const emailContext = {
  case_id: caseId,
  case_view_token: token,
  hub_case_url: hubCaseUrl,

  department,
  priority,
  status,

  case_type: pickFirst(
    caseUpdate.case_type,
    finalCase.last_intent,
    service.dominant_service,
    "consulta_general"
  ),

  service_code: serviceCode,
  case_origin_type: caseOriginType,
  service_label: serviceLabel,

  source_table: sourceTable || null,
  source_id: sourceId || null,

  customer: {
    name: customerName,
    wa_id: waId,
    email: customerEmail,
    rut: customerRut,
    address: addressFull,
    address_full: addressFull,
    city,
    id_customer: idCustomer
  },

  customer_reply: {
    detected_intent: replyIntent,
    action: replyAction,
    message: messageText,
    replied_at: normalizeDateTime(replyAt),
    raw_replied_at: replyAt || null
  },

  maintenance: maintenanceDetail,
  assembly: assemblyDetail,

  order: {
    id_order: idOrder,
    invoice_number: invoiceNumber
  },

  equipment: {
    product_names: productNames.length ? productNames : ["Sin productos informados"],
    product_references: productReferences.length ? productReferences : ["Sin referencias informadas"]
  },

  customer_detail_debug: {
    has_service_customer_detail: Object.keys(serviceCustomerDetail).length > 0,
    has_business_customer_detail: Object.keys(asObject(business.customer_detail)).length > 0,
    customer_detail_source: service.customer_detail_source || business.customer_detail_source || null
  },

  legacy_minimum_ready:
    !!customerName &&
