parameters.jsCode:
const data = $json;

return [
  {
    json: {
      handoff_manager: {
        name: "OPS_Handoff_Manager",
        version: "0.3.0",
        mode: "real"
      },
      result: {
        success: false,
        error: "invalid_handoff_input",
        reason: "No se puede crear ni actualizar caso porque falta wa_id.",
