const data = $("Code - Prepare Update Existing Case Query").item.json || {};

let previousCase = {};
try {
  previousCase = $("MySQL - Get Existing Active Case").item.json || {};
} catch (e) {
  previousCase = {};
}

return [
  {
    json: {
      ...data,
