const data = $("Code - Build Case Identity").item.json || {};
const existing = $("MySQL - Get Existing Active Case").item.json || {};

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function lower(value) {
  return clean(value).toLowerCase();
}

function pickFirstText(...values) {
  for (const value of values) {
    const v = clean(value);
    if (v) return v;
  }
  return "";
}

function pickFirstNumber(...values) {
  for (const value of values) {
    if (value === null || value === undefined || value === "") continue;
    const n = Number(value);
    if (Number.isFinite(n) && n > 0) return n;
  }
  return null;
}

function sqlString(value) {
  if (value === null || value === undefined || value === "") return "NULL";
  return `'${String(value).replace(/\\/g, "\\\\").replace(/'/g, "''")}'`;
}

function sqlNumber(value) {
  const n = Number(value);
  if (!Number.isFinite(n) || n <= 0) return "NULL";
  return String(n);
}

function sqlBool(value) {
  return value ? "1" : "0";
}

function priorityRank(value) {
  const v = lower(value);
  if (["urgent", "critical", "critica", "crítica"].includes(v)) return 4;
  if (["high", "alta"].includes(v)) return 3;
  if (["normal", "medium", "media"].includes(v)) return 2;
  if (["low", "baja"].includes(v)) return 1;
  return 0;
}

function isGenericService(value) {
  const v = lower(value);
  return ["", "unknown", "organic", "organic_whatsapp", "consulta_general"].includes(v);
}

function isGenericTopic(value) {
  const v = lower(value);
  return ["", "consulta_general", "contacto_humano"].includes(v);
}

const identity = data.handoff_case_identity || {};
const inputEvent = data.input_event || {};
const customerContext = data.customer_context || {};
const caseUpdate = data.case_update || {};

const existingId = pickFirstNumber(existing.id);
if (!existingId) {
  throw new Error("No existing case found for update branch.");
}

const waId = pickFirstText(identity.wa_id, existing.wa_id);
const contactName = pickFirstText(existing.contact_name, customerContext.full_name, inputEvent.contact_name, data.raw?.contact_name);
const phoneNumberId = pickFirstText(identity.phone_number_id, existing.phone_number_id);
const customerKey = pickFirstText(identity.customer_key, existing.customer_key);
const idCustomer = pickFirstNumber(identity.id_customer, existing.id_customer);
const idOrder = pickFirstNumber(identity.id_order, existing.id_order);
const invoiceNumber = pickFirstNumber(identity.invoice_number, existing.invoice_number);
const sourceTable = pickFirstText(identity.source_table, existing.source_table);
const sourceId = pickFirstNumber(identity.source_id, existing.source_id);

const newServiceCode = pickFirstText(identity.service_code, caseUpdate.service_code, existing.service_code);
const newCaseTopic = pickFirstText(identity.case_topic, caseUpdate.case_type, existing.case_topic);
const newCaseOriginType = pickFirstText(identity.case_origin_type, existing.case_origin_type);
const newScopeKey = pickFirstText(identity.case_scope_key, existing.case_scope_key);
const newThreadKey = pickFirstText(identity.case_thread_key, existing.case_thread_key);
const newActiveScopeKey = pickFirstText(identity.active_scope_key, newScopeKey, existing.active_scope_key);

const existingServiceCode = clean(existing.service_code);
const existingCaseTopic = clean(existing.case_topic);

const desiredServiceCode =
  newServiceCode && (isGenericService(existingServiceCode) || lower(newServiceCode) === "reclamo")
    ? newServiceCode
    : existingServiceCode || newServiceCode;

const desiredCaseTopic =
  newCaseTopic && (isGenericTopic(existingCaseTopic) || lower(newCaseTopic) === "reclamo")
    ? newCaseTopic
    : existingCaseTopic || newCaseTopic;

const desiredCaseOriginType = clean(existing.case_origin_type) || newCaseOriginType || null;

const currentPriority = pickFirstText(existing.priority, "normal");
const incomingPriority = pickFirstText(caseUpdate.priority, "high");
const desiredPriority =
  priorityRank(incomingPriority) > priorityRank(currentPriority)
    ? incomingPriority
    : currentPriority;

const shouldUpgradeCustomerKey =
  lower(existing.customer_key).startsWith("wa:") &&
  lower(customerKey).startsWith("prestashop:");

const shouldUpgradeIdentity =
  (!!sourceTable && !!sourceId && (!clean(existing.source_table) || !pickFirstNumber(existing.source_id))) ||
  (!!idOrder && !pickFirstNumber(existing.id_order)) ||
  (desiredCaseTopic && isGenericTopic(existing.case_topic)) ||
  (desiredServiceCode && isGenericService(existing.service_code));

const desiredCustomerKey = shouldUpgradeCustomerKey ? customerKey : pickFirstText(existing.customer_key, customerKey);
const desiredScopeKey = shouldUpgradeIdentity ? newScopeKey : pickFirstText(existing.case_scope_key, newScopeKey);
const desiredThreadKey = shouldUpgradeIdentity ? newThreadKey : pickFirstText(existing.case_thread_key, newThreadKey);
const desiredActiveScopeKey = shouldUpgradeIdentity ? newActiveScopeKey : pickFirstText(existing.active_scope_key, newActiveScopeKey);
const desiredActiveCaseKey = shouldUpgradeIdentity
  ? pickFirstText(newActiveScopeKey, newScopeKey, existing.active_case_key)
  : pickFirstText(existing.active_case_key, newActiveScopeKey, newScopeKey);

const providerMessageId = pickFirstText(
  inputEvent.provider_message_id,
  existing.last_message_id
);

const nowSql = "CONVERT_TZ(UTC_TIMESTAMP(), '+00:00', '-04:00')";

const query = `
UPDATE n8n_conversation_cases
SET
  wa_id = COALESCE(${sqlString(waId)}, wa_id),
  contact_name = COALESCE(${sqlString(contactName)}, contact_name),
  phone_number_id = COALESCE(${sqlString(phoneNumberId)}, phone_number_id),

  customer_key = COALESCE(${sqlString(desiredCustomerKey)}, customer_key),
  case_scope_key = COALESCE(${sqlString(desiredScopeKey)}, case_scope_key),
  case_thread_key = COALESCE(${sqlString(desiredThreadKey)}, case_thread_key),
  case_topic = COALESCE(${sqlString(desiredCaseTopic)}, case_topic),
  active_scope_key = COALESCE(${sqlString(desiredActiveScopeKey)}, active_scope_key),
  active_case_key = COALESCE(${sqlString(desiredActiveCaseKey)}, active_case_key),

  service_code = COALESCE(${sqlString(desiredServiceCode)}, service_code),
  case_origin_type = COALESCE(${sqlString(desiredCaseOriginType)}, case_origin_type),
  source_table = COALESCE(source_table, ${sqlString(sourceTable)}),
  source_id = COALESCE(source_id, ${sqlNumber(sourceId)}),
  id_order = COALESCE(id_order, ${sqlNumber(idOrder)}),
  id_customer = COALESCE(id_customer, ${sqlNumber(idCustomer)}),
  invoice_number = COALESCE(invoice_number, ${sqlNumber(invoiceNumber)}),

  department = COALESCE(department, ${sqlString(caseUpdate.department || "SAC")}),
  priority = ${sqlString(desiredPriority)},
  status = 'human_required',
  lifecycle_status = 'waiting_human',
  requires_human = 1,

  first_intent = COALESCE(first_intent, ${sqlString(desiredCaseTopic)}),
  last_intent = ${sqlString(desiredCaseTopic)},
  final_action = 'handoff_to_human',

  last_message_id = COALESCE(${sqlString(providerMessageId)}, last_message_id),
  last_message_at = ${nowSql},
  message_count = COALESCE(message_count, 0) + 1,

  notification_sent = CASE
    WHEN ${sqlBool(shouldUpgradeIdentity)} = 1 THEN 0
    ELSE notification_sent
  END,
  notification_sent_at = CASE
    WHEN ${sqlBool(shouldUpgradeIdentity)} = 1 THEN NULL
    ELSE notification_sent_at
  END,

  updated_at = ${nowSql}
WHERE id = ${sqlNumber(existingId)}
LIMIT 1;
`;

return [
  {
    json: {
      ...data,
      existing_case_id: existingId,
      case_operation: "update_existing",
      update_existing_case_query: query
    }
  }
];

