const identity = data.handoff_case_identity || {};
const inputEvent = data.input_event || {};
const customerContext = data.customer_context || {};
const caseUpdate = data.case_update || {};

const waId = pickFirstText(identity.wa_id, inputEvent.wa_id, inputEvent.phone_normalized);
const contactName = pickFirstText(customerContext.full_name, inputEvent.contact_name, data.raw?.contact_name);
const phoneNumberId = pickFirstText(identity.phone_number_id, inputEvent.phone_number_id);

const customerKey = pickFirstText(identity.customer_key);
const caseScopeKey = pickFirstText(identity.case_scope_key);
const caseThreadKey = pickFirstText(identity.case_thread_key);
const caseTopic = pickFirstText(identity.case_topic, "consulta_general");
const activeScopeKey = pickFirstText(identity.active_scope_key, caseScopeKey);
