)
SELECT
  ${sqlString(activeCaseKey)},
  ${sqlString(customerKey)},
  ${sqlString(caseScopeKey)},
  ${sqlString(caseThreadKey)},
  ${sqlString(caseTopic)},
  ${sqlString(waId)},
  ${sqlString(contactName)},
  ${sqlString(phoneNumberId)},
  'whatsapp',
  'meta',
  ${sqlString(department)},
  'human_required',
  'waiting_human',
  ${nowSql},
  NULL,
  NULL,
  ${sqlString(activeScopeKey)},
  ${sqlString(priority)},
  ${sqlString(serviceCode)},
  ${sqlString(caseOriginType)},
  ${sqlString(sourceTable)},
  ${sqlNumber(sourceId)},
  ${sqlNumber(idOrder)},
  ${sqlNumber(idCustomer)},
  ${sqlNumber(invoiceNumber)},
  ${sqlString(providerMessageId)},
  ${sqlString(providerMessageId)},
  ${sqlString(caseTopic)},
  ${sqlString(caseTopic)},
  'handoff_to_human',
  1,
  0,
  1,
  0,
  ${nowSql},
  ${nowSql},
  ${nowSql},
  ${nowSql},
  SHA2(CONCAT(${sqlString(waId)}, '|', UTC_TIMESTAMP(), '|', RAND()), 256)
FROM DUAL
WHERE NOT EXISTS (
  SELECT 1
  FROM n8n_conversation_cases
  WHERE
    ${activeLifecycleSql}
    AND (
      (
        source_table = ${sqlString(sourceTable)}
        AND source_id = ${sqlNumber(sourceId)}
        AND ${sourceTable && sourceId ? "1 = 1" : "0 = 1"}
      )
      OR
      (
        customer_key = ${sqlString(customerKey)}
        AND id_order = ${sqlNumber(idOrder)}
        AND ${customerKey && idOrder ? "1 = 1" : "0 = 1"}
      )
      OR
      (
        id_customer = ${sqlNumber(idCustomer)}
        AND id_order = ${sqlNumber(idOrder)}
        AND ${idCustomer && idOrder ? "1 = 1" : "0 = 1"}
      )
      OR
      (
        active_scope_key = ${sqlString(activeScopeKey)}
        AND ${activeScopeKey ? "1 = 1" : "0 = 1"}
      )
      OR
      (
        active_case_key = ${sqlString(activeCaseKey)}
        AND ${activeCaseKey ? "1 = 1" : "0 = 1"}
      )
      OR
      (
        case_scope_key = ${sqlString(caseScopeKey)}
        AND ${caseScopeKey ? "1 = 1" : "0 = 1"}
      )
      OR
      (
        wa_id = ${sqlString(waId)}
        AND id_order = ${sqlNumber(idOrder)}
        AND ${waId && idOrder ? "1 = 1" : "0 = 1"}
      )
    )
  LIMIT 1
)
ON DUPLICATE KEY UPDATE
  customer_key = COALESCE(VALUES(customer_key), customer_key),
  case_scope_key = COALESCE(VALUES(case_scope_key), case_scope_key),
  case_thread_key = COALESCE(VALUES(case_thread_key), case_thread_key),
  case_topic = COALESCE(VALUES(case_topic), case_topic),
  active_scope_key = COALESCE(VALUES(active_scope_key), active_scope_key),

  wa_id = COALESCE(VALUES(wa_id), wa_id),
